const assert = require("assert");
const { diffArray } = require("../question-01/index.js");
let passed = 0, failed = 0;
function runTest(name, fn) { try { fn(); passed++; console.log("PASS: " + name); } catch(e) { failed++; console.log("FAIL: " + name + " — " + e.message); } }
runTest("basic sym diff", () => { assert.deepStrictEqual(diffArray([1,2,3,5],[1,2,3,4,5]).sort(), [4]); });
runTest("string sym diff", () => { assert.deepStrictEqual(diffArray(["diorite","andesite","grass"],["diorite","andesite","grass","dirt"]), ["dirt"]); });
runTest("empty vs non-empty", () => { assert.deepStrictEqual(diffArray([],["snuffleupagus"]), ["snuffleupagus"]); });
runTest("identical arrays", () => { assert.deepStrictEqual(diffArray([1,2,3],[1,2,3]), []); });
console.log("\n" + passed + "/" + (passed+failed) + " tests passed");
if (failed > 0) process.exit(1);
